import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.Cd7uensT.js";const c=JSON.parse('{"title":"工单管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/ticket-management.md","filePath":"guide/features/ticket-management.md","lastUpdated":1781673626000}'),o={name:"guide/features/ticket-management.md"};function l(n,t,i,s,h,g){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="工单管理" tabindex="-1">工单管理 <a class="header-anchor" href="#工单管理" aria-label="Permalink to &quot;工单管理&quot;">​</a></h1><h2 id="工单列表" tabindex="-1">工单列表 <a class="header-anchor" href="#工单列表" aria-label="Permalink to &quot;工单列表&quot;">​</a></h2><h3 id="工单状态" tabindex="-1">工单状态 <a class="header-anchor" href="#工单状态" aria-label="Permalink to &quot;工单状态&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>待处理 → 处理中 → 已完成 → 已关闭</span></span></code></pre></div><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><strong>待处理</strong></td><td>新建工单，等待分配</td></tr><tr><td><strong>处理中</strong></td><td>正在处理</td></tr><tr><td><strong>已完成</strong></td><td>问题已解决</td></tr><tr><td><strong>已关闭</strong></td><td>工单关闭</td></tr></tbody></table><h3 id="工单优先级" tabindex="-1">工单优先级 <a class="header-anchor" href="#工单优先级" aria-label="Permalink to &quot;工单优先级&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优先级</th><th>说明</th><th>响应时间</th></tr></thead><tbody><tr><td><strong>紧急</strong></td><td>严重影响业务</td><td>立即响应</td></tr><tr><td><strong>高</strong></td><td>重要问题</td><td>2小时内</td></tr><tr><td><strong>中</strong></td><td>一般问题</td><td>24小时内</td></tr><tr><td><strong>低</strong></td><td>优化建议</td><td>一周内</td></tr></tbody></table><h3 id="创建工单" tabindex="-1">创建工单 <a class="header-anchor" href="#创建工单" aria-label="Permalink to &quot;创建工单&quot;">​</a></h3><ol><li>进入「工单列表」页面</li><li>点击「新建工单」</li><li>填写工单信息：标题、故障分类、优先级、关联设备、问题描述、附件等</li><li>提交工单</li></ol><h3 id="处理工单" tabindex="-1">处理工单 <a class="header-anchor" href="#处理工单" aria-label="Permalink to &quot;处理工单&quot;">​</a></h3><ol><li>点击工单进入详情页</li><li>点击「接单」分配给自己</li><li>更新工单状态为「处理中」</li><li>记录处理过程</li><li>问题解决后，点击「完成」</li></ol><h3 id="工单关联设备" tabindex="-1">工单关联设备 <a class="header-anchor" href="#工单关联设备" aria-label="Permalink to &quot;工单关联设备&quot;">​</a></h3><p>在创建或编辑工单时，支持将工单与一个或多个设备进行关联：</p><ul><li><strong>关联方式</strong>：在工单表单中点击「选择设备」按钮，从设备列表中勾选目标设备</li><li><strong>关联展示</strong>：工单详情页顶部展示关联设备列表，点击设备名称可快速跳转至设备详情页</li><li><strong>设备工单追溯</strong>：在设备详情页的「工单历史」标签页中，可查看与该设备相关的所有历史工单</li><li><strong>关联解除</strong>：在工单详情页点击设备列表中的「解除关联」按钮，可移除工单与设备的关联关系</li></ul><p>通过设备关联，运维人员可在处理设备故障时快速了解该设备的历史问题，辅助故障诊断。</p><h2 id="故障分类" tabindex="-1">故障分类 <a class="header-anchor" href="#故障分类" aria-label="Permalink to &quot;故障分类&quot;">​</a></h2><p>故障分类用于标准化故障类型，便于后续统计分析和运维流程优化。</p><h3 id="分类层级" tabindex="-1">分类层级 <a class="header-anchor" href="#分类层级" aria-label="Permalink to &quot;分类层级&quot;">​</a></h3><p>支持多级分类结构，默认提供以下一级分类：</p><table tabindex="0"><thead><tr><th>分类</th><th>说明</th><th>示例子类</th></tr></thead><tbody><tr><td><strong>硬件故障</strong></td><td>设备硬件相关问题</td><td>硬盘故障、内存故障、电源故障、风扇故障、主板故障</td></tr><tr><td><strong>网络故障</strong></td><td>网络连接相关问题</td><td>端口 Down、链路中断、带宽异常、DNS 解析失败</td></tr><tr><td><strong>系统故障</strong></td><td>操作系统或软件问题</td><td>系统崩溃、服务异常、进程挂死、配置错误</td></tr><tr><td><strong>环境故障</strong></td><td>机房环境相关问题</td><td>温度过高、湿度异常、漏水告警、供电异常</td></tr><tr><td><strong>安全事件</strong></td><td>安全相关告警</td><td>异常登录、病毒告警、端口扫描、DDoS 攻击</td></tr><tr><td><strong>其他</strong></td><td>以上未涵盖的故障类型</td><td>—</td></tr></tbody></table><h3 id="管理故障分类" tabindex="-1">管理故障分类 <a class="header-anchor" href="#管理故障分类" aria-label="Permalink to &quot;管理故障分类&quot;">​</a></h3><ol><li>进入「系统管理」→「故障分类配置」页面</li><li>支持新增、编辑、删除故障分类</li><li>支持拖拽排序和父子层级管理</li><li>修改后的分类结构将同步到工单创建表单的故障分类下拉选项</li></ol><h2 id="统计报表" tabindex="-1">统计报表 <a class="header-anchor" href="#统计报表" aria-label="Permalink to &quot;统计报表&quot;">​</a></h2><p>统计报表模块提供工单数据的多维度分析，辅助管理决策。</p><h3 id="报表视图" tabindex="-1">报表视图 <a class="header-anchor" href="#报表视图" aria-label="Permalink to &quot;报表视图&quot;">​</a></h3><table tabindex="0"><thead><tr><th>报表类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>工单数量趋势</strong></td><td>按日/周/月展示工单创建量的变化趋势，折线图展示</td></tr><tr><td><strong>分类统计</strong></td><td>按故障分类统计工单数量，饼图/柱状图展示各类占比</td></tr><tr><td><strong>处理效率</strong></td><td>统计工单平均响应时间、平均处理时长、按时完成率等效率指标</td></tr><tr><td><strong>人员统计</strong></td><td>按处理人统计工单数量、完成率、平均处理时长</td></tr><tr><td><strong>优先级分布</strong></td><td>按优先级展示工单数量分布</td></tr><tr><td><strong>状态分布</strong></td><td>按工单状态（待处理、处理中、已完成、已关闭）统计数量</td></tr></tbody></table><h3 id="报表筛选" tabindex="-1">报表筛选 <a class="header-anchor" href="#报表筛选" aria-label="Permalink to &quot;报表筛选&quot;">​</a></h3><ul><li>支持按时间范围筛选（自定义起止时间、预设快捷时间如近 7 天、近 30 天、近 90 天）</li><li>支持按故障分类筛选</li><li>支持按工单优先级筛选</li><li>支持按处理人筛选</li></ul><h3 id="报表导出" tabindex="-1">报表导出 <a class="header-anchor" href="#报表导出" aria-label="Permalink to &quot;报表导出&quot;">​</a></h3><p>统计报表支持导出为图片（PNG）或数据表格（Excel），方便用于运维报告和复盘分析。</p><h2 id="字段管理" tabindex="-1">字段管理 <a class="header-anchor" href="#字段管理" aria-label="Permalink to &quot;字段管理&quot;">​</a></h2><p>工单字段管理用于自定义工单属性，满足不同运维场景下的信息收集需求。</p><h3 id="支持字段类型" tabindex="-1">支持字段类型 <a class="header-anchor" href="#支持字段类型" aria-label="Permalink to &quot;支持字段类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>文本</strong></td><td>单行文本输入</td></tr><tr><td><strong>多行文本</strong></td><td>长文本输入</td></tr><tr><td><strong>数字</strong></td><td>数值输入</td></tr><tr><td><strong>日期</strong></td><td>日期选择器</td></tr><tr><td><strong>日期时间</strong></td><td>日期+时间选择器</td></tr><tr><td><strong>下拉选择</strong></td><td>单选下拉框，可自定义选项列表</td></tr><tr><td><strong>多选</strong></td><td>多选下拉框，可同时选择多个选项</td></tr><tr><td><strong>开关</strong></td><td>布尔值开关</td></tr><tr><td><strong>附件</strong></td><td>文件上传</td></tr></tbody></table><h3 id="管理自定义字段" tabindex="-1">管理自定义字段 <a class="header-anchor" href="#管理自定义字段" aria-label="Permalink to &quot;管理自定义字段&quot;">​</a></h3><ol><li>进入「工单管理」页面 → 「字段管理」标签页</li><li>点击「新增字段」按钮</li><li>填写字段信息：字段名称、字段类型、是否必填、排序、默认值、选项列表（下拉/多选类型需要）</li><li>保存后，自定义字段将自动出现在工单创建和编辑表单中</li></ol><p>操作方式与设备字段管理保持一致，确保用户在不同模块间有一致的操作体验。</p>',37)])])}const u=a(o,[["render",l]]);export{c as __pageData,u as default};
